ee:message.ee:set-payload:
          %dw 2.0
output application/json
---
{
  jsonrpc: "2.0",
  id: correlationId,
  method: "message/send",
  params: {
    message: {
      kind: "message",
      role: "user",
      messageId: correlationId,
      parts: [
        { kind: "text", text: vars.userRequest }
      ]
    }
  }
}
